package main

import (
    "fmt"
    "os/exec"
    "path/filepath"
)

func ConvertImage(inputFile, outputFile, format string) error {
    if inputFile == "" || outputFile == "" || format == "" {
        return fmt.Errorf("inputFile, outputFile, and format must not be empty")
    }

    outputExt := fmt.Sprintf(".%s", format)
    if filepath.Ext(outputFile) != outputExt {
        outputFile = fmt.Sprintf("%s%s", outputFile, outputExt)
    }

    cmd := exec.Command("convert", inputFile, "-define", fmt.Sprintf("%s:extent=0", format), outputFile)
    output, err := cmd.CombinedOutput()
    if err != nil {
        return fmt.Errorf("failed to convert image: %v, output: %s", err, output)
    }

    return nil
}